68	function isMarketStatus(value: unknown): value is MarketStatus {
69	  return value === "active" || value === "resolved" || value === "closed" || value === "draft";
70	}
71	
72	function isRecord(value: unknown): value is Record<string, unknown> {
73	  return typeof value === "object" && value !== null;
74	}
75	
76	function parseMarginals(value: unknown): Record<string, number> | null {
77	  if (!isRecord(value)) {
78	    return null;
79	  }
80	
81	  const marginals: Record<string, number> = {};
82	  for (const [outcomeId, probability] of Object.entries(value)) {
83	    if (typeof probability !== "number" || !Number.isFinite(probability)) {
84	      return null;
85	    }
86	    marginals[outcomeId] = probability;
87	  }
88	  return marginals;
89	}
90	
91	function parseMarketPriceMessage(value: unknown): MarketPriceMessage | null {
92	  if (!isRecord(value)) {
93	    return null;
94	  }
95	
96	  if (
97	    typeof value.marketId !== "string"
98	    || !isMarketStatus(value.status)
99	    || typeof value.seq !== "number"
100	    || !Number.isFinite(value.seq)
101	    || typeof value.emittedAt !== "string"
102	    || typeof value.approxFlag !== "boolean"
103	  ) {
104	    return null;
105	  }
106	
107	  const marginals = parseMarginals(value.marginals);
108	  if (!marginals) {
109	    return null;
110	  }
111	
112	  let resolutionProbabilities: Record<string, number> | undefined;
113	  if (value.resolutionProbabilities != null) {
114	    const parsedResolutionProbabilities = parseMarginals(value.resolutionProbabilities);
115	    if (!parsedResolutionProbabilities) {
116	      return null;
117	    }
118	    resolutionProbabilities = parsedResolutionProbabilities;
119	  }
120	
121	  return {
122	    marketId: value.marketId,
123	    status: value.status,
124	    marginals,
125	    seq: value.seq,
126	    emittedAt: value.emittedAt,
127	    approxFlag: value.approxFlag,
128	    resolution: typeof value.resolution === "string" ? value.resolution : undefined,
129	    resolutionProbabilities,
130	  };
131	}
